SELECT FROM t_article a LEFT JOIN t_book b ON a.book_id = b.id WHERE 1=1
AND (a.title LIKE CONCAT('%', #{keyword}, '%'))
AND a.book_id = #{bookId}
AND a.difficulty = #{difficulty}
ORDER BY a.create_time DESC

mapper.update:
UPDATE t_article
book_id = #{bookId}, title = #{title}, content = #{content}, translation = #{translation}, difficulty = #{difficulty}, word_count = #{wordCount}, audio_url = #{audioUrl}, status = #{status},
WHERE id = #{id}
